import { useEffect, useState } from 'react';
import { Mail, Github, Linkedin } from 'lucide-react';
import { useApp } from '../context/AppContext';
import t from '../i18n/translations';
import { glass } from '../utils/glass';

const phrasesEn = ['Cybersecurity Enthusiast','AI & Gen AI Practitioner','Web Developer','Network Enthusiast','MIS Student'];
const phrasesAr = ['متحمس للأمن السيبراني','ممارس للذكاء الاصطناعي','مطور ويب','متحمس للشبكات','طالب نظم معلومات'];

export default function Hero() {
  const { dark, lang } = useApp();
  const tr = t[lang];
  const phrases = lang === 'ar' ? phrasesAr : phrasesEn;

  const [text, setText] = useState('');
  const [pi, setPi] = useState(0);
  const [ci, setCi] = useState(0);
  const [del, setDel] = useState(false);

  useEffect(() => { setText(''); setCi(0); setPi(0); setDel(false); }, [lang]);

  useEffect(() => {
    const phrase = phrases[pi];
    const timer = setTimeout(() => {
      if (!del) {
        setText(phrase.slice(0, ci + 1));
        if (ci + 1 === phrase.length) { setTimeout(() => setDel(true), 1600); return; }
        setCi(c => c + 1);
      } else {
        setText(phrase.slice(0, ci - 1));
        if (ci - 1 === 0) { setDel(false); setPi(p => (p + 1) % phrases.length); setCi(0); return; }
        setCi(c => c - 1);
      }
    }, del ? 45 : 90);
    return () => clearTimeout(timer);
  }, [ci, pi, del, phrases]);

  const bg     = dark ? '#0f0f14' : '#fdfcf9';
  const tBase  = dark ? '#f0f0f8' : '#1a1a2e';
  const tMuted = dark ? 'rgba(255,255,255,0.5)' : '#5a5a72';

  return (
    <section id="hero"
      style={{ background: bg, minHeight: '100vh' }}
      className="grid md:grid-cols-2 items-center gap-8 px-[5%] relative overflow-hidden transition-colors duration-300">

      {/* Background blobs */}
      <div className="blob-hero w-[560px] h-[560px] bg-amber opacity-[0.08] top-[-100px] right-[-120px]" />
      <div className="blob-hero-2 w-[300px] h-[300px] bg-teal opacity-[0.06] bottom-[-50px] left-[30%]" />

      {/* ─── LEFT ─── */}
      <div className="relative z-10 pt-24 pb-10 md:pb-0 md:pt-0">
        <p className="text-lg mb-1" style={{ color: tMuted }}>{tr.hiIm}</p>

        <h1 className="font-serif-display leading-[1.02] tracking-tight">
          <span className="block text-5xl md:text-7xl" style={{ color: tBase }}>Kareem Basem</span>
          <em className="block text-5xl md:text-7xl text-amber not-italic font-serif-display">Fathi.</em>
        </h1>

        <div className="flex items-center gap-2 mt-5 text-sm font-medium">
          <span className="text-amber font-bold">→</span>
          <span className="font-semibold" style={{ color: tBase }}>{text}</span>
          <span className="text-amber animate-[ping2_1s_step-end_infinite]">|</span>
        </div>

        <p className="mt-4 text-[0.95rem] leading-[1.8] max-w-[440px]" style={{ color: tMuted }}>
          {tr.heroDesc}
        </p>

        <div className="flex gap-3 flex-wrap mt-7">
          <a href="#projects"
            className="px-6 py-3 font-semibold text-sm rounded-full transition-all hover:-translate-y-1"
            style={{ background: '#f0a500', color: '#fff', boxShadow: '0 4px 20px rgba(240,165,0,0.3)' }}
            onMouseEnter={e => e.target.style.boxShadow = '0 8px 28px rgba(240,165,0,0.45)'}
            onMouseLeave={e => e.target.style.boxShadow = '0 4px 20px rgba(240,165,0,0.3)'}>
            {tr.viewWork}
          </a>
          <a href="#contact"
            className="px-6 py-3 font-semibold text-sm rounded-full transition-all hover:-translate-y-1"
            style={{
              ...glass(dark),
              color: dark ? 'rgba(255,255,255,0.8)' : '#1a1a2e',
            }}>
            {tr.getInTouch}
          </a>
        </div>

        <div className="flex items-center gap-3 mt-7">
          <span className="text-xs uppercase tracking-wider font-medium" style={{ color: tMuted }}>{tr.findMe}</span>
          {[
            { href:'https://www.linkedin.com/in/karem-basem', Icon: Linkedin },
            { href:'https://github.com/Kareem-Basem', Icon: Github },
            { href:'mailto:karemalwy1@gmail.com', Icon: Mail },
          ].map(({ href, Icon }, i) => (
            <a key={i} href={href} target={href.startsWith('http') ? '_blank' : undefined} rel="noreferrer"
              className="w-9 h-9 rounded-full flex items-center justify-center transition-all hover:-translate-y-0.5 hover:text-amber"
              style={{ ...glass(dark), color: tMuted }}>
              <Icon size={15} />
            </a>
          ))}
        </div>
      </div>

      {/* ─── RIGHT — Photo ─── */}
      <div className="hidden md:flex flex-col items-center gap-5 relative z-10">
        <div className="relative w-[320px] h-[320px] float">
          {/* Blob ring */}
          <div className="blob-avatar absolute inset-0 bg-gradient-to-br from-amber to-[#ffd166] opacity-90" />

          {/* Photo */}
          <div className="absolute inset-[20px] rounded-full overflow-hidden"
            style={{ boxShadow: '0 8px 32px rgba(26,26,46,0.2)' }}>
            <img
              src={process.env.PUBLIC_URL + '/assets/photo/kareem.jpg'}
              alt="Kareem Basem Fathi"
              className="w-full h-full object-cover"
              style={{ objectPosition: 'center 15%' }}
            />
          </div>

          {/* Open to Work badge */}
          <div className="absolute top-3 -right-8 rounded-2xl px-3 py-2 shadow-xl flex items-center gap-2"
            style={{ ...glass(dark), minWidth: 140 }}>
            <span className="w-2 h-2 rounded-full bg-green-500 flex-shrink-0 ping2 block" />
            <div>
              <div className="text-[0.78rem] font-semibold" style={{ color: tBase }}>{tr.openToWork}</div>
              <div className="text-[0.62rem]" style={{ color: tMuted }}>{tr.availableNow}</div>
            </div>
          </div>

          {/* Certs count badge */}
          <div className="absolute bottom-6 -left-10 rounded-2xl px-3 py-2 shadow-xl flex items-center gap-2"
            style={glass(dark)}>
            <span className="font-serif-display text-2xl italic text-teal font-bold">20+</span>
            <div className="text-[0.65rem] leading-tight" style={{ color: tMuted }}>
              {tr.certifications}<br />{tr.earned}
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}
